	scores := engine.Score(nil, policy.EvaluationResult{Passed: true}, "go")
	if len(scores) != 0 {
		t.Errorf("no evidence should produce empty scores, got %d dimensions", len(scores))
	}
	avg := scores.WeightedAverage(nil)
	if avg != 0 {
